BEGIN TRANSACTION;
CREATE TABLE "favorites" (user_id INTEGER, url TEXT, title TEXT, PRIMARY KEY(user_id, url));
CREATE TABLE music_play_counts (
                guild_id INTEGER,
                url TEXT,
                title TEXT,
                play_count INTEGER DEFAULT 1,
                PRIMARY KEY(guild_id, url)
            );
CREATE TABLE music_settings (
                guild_id INTEGER PRIMARY KEY,
                volume REAL DEFAULT 1.0
            );
CREATE TABLE "users" (
                user_id INTEGER,
                guild_id INTEGER,
                xp INTEGER DEFAULT 0,
                level INTEGER DEFAULT 1,
                total_vc_seconds INTEGER DEFAULT 0, birth_month INTEGER, birth_day INTEGER,
                PRIMARY KEY (user_id, guild_id)
            );
CREATE TABLE watch_playlists (
                session_id TEXT,
                video_url TEXT,
                video_title TEXT,
                added_by TEXT,
                order_index INTEGER,
                PRIMARY KEY (session_id, video_url)
            );
CREATE TABLE watch_sessions (
                session_id TEXT PRIMARY KEY,
                guild_id INTEGER,
                created_by INTEGER,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            , channel_id INTEGER, message_id INTEGER);
COMMIT;
